/* BTStepNumber — Figma node 3007-2442
 *
 * Shared by Vue (imported here) and React (same file in React package).
 * All var() names verified against packages/tokens/platforms/web/bspace/dist/styles.css.
 * No hex fallback per CLAUDE.md §6.
 */

.bt-step-number {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  padding: var(--space-sm);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: 1;
  color: var(--text-primary);
  background: transparent;
  cursor: pointer;
  box-sizing: border-box;
  transition: background 100ms ease, border-color 100ms ease;
  flex-shrink: 0;
}

.bt-step-number:hover:not(.bt-step-number--active):not(.bt-step-number--disabled):not(.bt-step-number--ellipsis) {
  background: var(--bg-subtle);
}

/* Active — subtle bg + brand border */
.bt-step-number--active {
  background: var(--bg-subtle);
  border-color: var(--color-brand-primary);
}

/* Disabled — no border, muted text */
.bt-step-number--disabled {
  border: none;
  color: var(--text-disabled);
  cursor: not-allowed;
}

/* Ellipsis — no border, secondary text, non-interactive */
.bt-step-number--ellipsis {
  border: none;
  color: var(--text-secondary);
  cursor: default;
  pointer-events: none;
}

/* SVG icon inside ellipsis pill */
.bt-step-number__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
}

.bt-step-number__icon > svg {
  width: 16px;
  height: 16px;
  display: block;
}

/**
 * BTStepNumber — reusable step/page pill (React).
 * Figma: node 3007-2442.
 *
 * @example
 * ```tsx
 * // Normal page pill
 * <BTStepNumber page={3} isActive={currentPage === 3} onClick={() => setPage(3)} />
 *
 * // Ellipsis placeholder
 * <BTStepNumber page={0} isEllipsis />
 *
 * // Disabled
 * <BTStepNumber page={2} isDisabled />
 * ```
 */
import './BTStepNumber.css';
import type { BTStepNumberProps } from './BTStepNumber.types';

// ── more_horiz icon (Figma exported path) ────────────────────────────────────

function IconMoreHoriz() {
  return (
    // viewBox centres the 10.67×2.67 dots to match Figma's 41.67%/16.67% inset in a 16px container
    <svg
      viewBox="-2.67 -6.67 16 16"
      fill="currentColor"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
    >
      <path d="M1.33333 2.66667C0.966667 2.66667 0.652778 2.53611 0.391667 2.275C0.130556 2.01389 0 1.7 0 1.33333C0 0.966667 0.130556 0.652778 0.391667 0.391667C0.652778 0.130556 0.966667 0 1.33333 0C1.7 0 2.01389 0.130556 2.275 0.391667C2.53611 0.652778 2.66667 0.966667 2.66667 1.33333C2.66667 1.7 2.53611 2.01389 2.275 2.275C2.01389 2.53611 1.7 2.66667 1.33333 2.66667ZM5.33333 2.66667C4.96667 2.66667 4.65278 2.53611 4.39167 2.275C4.13056 2.01389 4 1.7 4 1.33333C4 0.966667 4.13056 0.652778 4.39167 0.391667C4.65278 0.130556 4.96667 0 5.33333 0C5.7 0 6.01389 0.130556 6.275 0.391667C6.53611 0.652778 6.66667 0.966667 6.66667 1.33333C6.66667 1.7 6.53611 2.01389 6.275 2.275C6.01389 2.53611 5.7 2.66667 5.33333 2.66667ZM9.33333 2.66667C8.96667 2.66667 8.65278 2.53611 8.39167 2.275C8.13056 2.01389 8 1.7 8 1.33333C8 0.966667 8.13056 0.652778 8.39167 0.391667C8.65278 0.130556 8.96667 0 9.33333 0C9.7 0 10.0139 0.130556 10.275 0.391667C10.5361 0.652778 10.6667 0.966667 10.6667 1.33333C10.6667 1.7 10.5361 2.01389 10.275 2.275C10.0139 2.53611 9.7 2.66667 9.33333 2.66667Z" />
    </svg>
  );
}

// ── Component ────────────────────────────────────────────────────────────────

export function BTStepNumber({
  page,
  isActive = false,
  isDisabled = false,
  isEllipsis = false,
  onClick,
}: BTStepNumberProps) {
  const classes = [
    'bt-step-number',
    isActive    && 'bt-step-number--active',
    isDisabled  && 'bt-step-number--disabled',
    isEllipsis  && 'bt-step-number--ellipsis',
  ].filter(Boolean).join(' ');

  function handleClick() {
    if (!isDisabled && !isEllipsis) onClick?.();
  }

  return (
    <button
      className={classes}
      disabled={isDisabled || isEllipsis}
      aria-label={isEllipsis ? undefined : `Page ${page}`}
      aria-current={isActive ? 'page' : undefined}
      onClick={handleClick}
    >
      {isEllipsis ? (
        <span className="bt-step-number__icon">
          <IconMoreHoriz />
        </span>
      ) : (
        page
      )}
    </button>
  );
}

BTStepNumber.displayName = 'BTStepNumber';

/**
 * BTStepNumber — reusable step/page pill component types (React).
 * Mirror of Vue BTStepNumber.types.ts — keep in sync.
 *
 * Figma: node 3007-2442.
 */
export interface BTStepNumberProps {
  /** Page or step number to display. Ignored when `isEllipsis` is true. */
  page: number;
  /** Marks this pill as the current active page. @default false */
  isActive?: boolean;
  /** Disables interaction. @default false */
  isDisabled?: boolean;
  /** Shows the more_horiz (⋯) icon instead of a number. Non-interactive. @default false */
  isEllipsis?: boolean;
  /** Called when the pill is clicked. Not fired for disabled or ellipsis. */
  onClick?: () => void;
}
